import { useEffect, useState } from "react";
import axios from "axios";
import Navbar from "../components/Navbar";

export default function CustomerDashboard() {

  const [workers, setWorkers] =
    useState([]);

  const [requests, setRequests] =
    useState([]);

  const [search, setSearch] =
    useState("");

  const [searched, setSearched] =
    useState(false);

  const [date, setDate] =
    useState("");

  const [time1, setTime1] =
    useState("");

  const [time2, setTime2] =
    useState("");

  const [time3, setTime3] =
    useState("");


  // LOAD CUSTOMER REQUESTS

  useEffect(() => {

    fetchRequests();

  }, []);


  const fetchRequests = async () => {

    const user =
      JSON.parse(localStorage.getItem("user"));

    try {

      const res = await axios.get(
        `http://localhost:5000/api/request/customer/${user.name}`
      );

      setRequests(res.data);

    } catch (err) {

      console.log(err);
    }
  };


  // SEARCH WORKERS

  const searchWorkers = async () => {

    try {

      const res = await axios.get(
        "http://localhost:5000/api/auth/workers"
      );

      const filtered = res.data.filter(worker =>

        worker.skills?.some(skill =>

          skill.toLowerCase().includes(
            search.toLowerCase()
          )
        )
      );

      setWorkers(filtered);

      setSearched(true);

    } catch (err) {

      alert("Failed to fetch workers");
    }
  };


  // SEND REQUEST

  const sendRequest = async (worker) => {

    const user =
      JSON.parse(localStorage.getItem("user"));

    try {

      await axios.post(
        "http://localhost:5000/api/request/send",
        {

          customerName: user.name,

          labourId: worker._id,

          labourName: worker.name,

          workType: search,

          date: date,

          timings: [
            time1,
            time2,
            time3
          ],

          status: "Pending"
        }
      );

      alert("Request Sent");

      fetchRequests();

    } catch (err) {

      alert("Failed");
    }
  };


  // GET REQUEST STATUS

  const getRequest = (workerId) => {

    return requests.find(
      req => req.labourId === workerId
    );
  };

  return (

    <div style={styles.page}>

      <Navbar />

      <div style={styles.container}>

        {/* TOP */}

        <div style={styles.top}>

          <h1 style={styles.heading}>
            Find Workers
          </h1>

          <p style={styles.subtext}>
            Search workers and send requests
          </p>

        </div>

        {/* SEARCH */}

        <div style={styles.searchCard}>

          <input
            style={styles.input}
            placeholder="Search worker type..."
            value={search}
            onChange={(e) =>
              setSearch(e.target.value)
            }
          />

          <input
            type="date"
            style={styles.input}
            value={date}
            onChange={(e) =>
              setDate(e.target.value)
            }
          />

          <select
            style={styles.input}
            onChange={(e) =>
              setTime1(e.target.value)
            }
          >
            <option>Preferred Time 1</option>
            <option>9 AM - 11 AM</option>
            <option>11 AM - 1 PM</option>
            <option>2 PM - 4 PM</option>
            <option>4 PM - 6 PM</option>
          </select>

          <select
            style={styles.input}
            onChange={(e) =>
              setTime2(e.target.value)
            }
          >
            <option>Preferred Time 2</option>
            <option>9 AM - 11 AM</option>
            <option>11 AM - 1 PM</option>
            <option>2 PM - 4 PM</option>
            <option>4 PM - 6 PM</option>
          </select>

          <select
            style={styles.input}
            onChange={(e) =>
              setTime3(e.target.value)
            }
          >
            <option>Preferred Time 3</option>
            <option>9 AM - 11 AM</option>
            <option>11 AM - 1 PM</option>
            <option>2 PM - 4 PM</option>
            <option>4 PM - 6 PM</option>
          </select>

          <button
            style={styles.searchBtn}
            onClick={searchWorkers}
          >
            Search
          </button>

        </div>

        {/* EMPTY */}

        {searched && workers.length === 0 && (

          <div style={styles.empty}>
            No workers found
          </div>

        )}

        {/* WORKERS */}

        <div style={styles.grid}>

          {workers.map(worker => {

            const req =
              getRequest(worker._id);

            return (

              <div
                key={worker._id}
                style={styles.card}
              >

                {/* PROFILE */}

                <div style={styles.profile}>

                  <div style={styles.avatar}>
                    {worker.name?.charAt(0)}
                  </div>

                  <div>

                    <h2 style={styles.name}>
                      {worker.name}
                    </h2>

                    <p style={styles.skills}>
                      {worker.skills?.join(", ")}
                    </p>

                  </div>

                </div>

                {/* INFO */}

                <div style={styles.infoBox}>

                  <p style={styles.info}>
                    📍 {worker.city},
                    {" "}
                    {worker.area}
                  </p>

                  <p style={styles.info}>
                    📞 {worker.phone}
                  </p>

                  <p style={styles.price}>
                    ₹ {worker.price}
                  </p>

                </div>

                {/* STATUS */}

                {req && (

                  <div style={styles.statusBox}>

                    {req.status ===
                    "Pending" && (

                      <span
                        style={styles.pending}
                      >
                        Pending
                      </span>

                    )}

                    {req.status ===
                    "Accepted" && (

                      <span
                        style={styles.accepted}
                      >
                        Accepted • ₹
                        {" "}
                        {req.labourPrice}
                      </span>

                    )}

                    {req.status ===
                    "Rejected" && (

                      <span
                        style={styles.rejected}
                      >
                        Rejected
                      </span>

                    )}

                  </div>

                )}

                {/* BUTTON */}

                <button
                  style={styles.requestBtn}
                  onClick={() =>
                    sendRequest(worker)
                  }
                >
                  Send Request
                </button>

              </div>
            );
          })}

        </div>

      </div>

    </div>
  );
}

const styles = {

  page: {
    minHeight: "100vh",
    background: "#f5f7fb",
    fontFamily: "Arial"
  },

  container: {
    padding: "40px 60px"
  },

  top: {
    marginBottom: "30px"
  },

  heading: {
    fontSize: "30px",
    marginBottom: "8px",
    color: "#111827"
  },

  subtext: {
    color: "#6b7280"
  },

  searchCard: {
    background: "white",
    padding: "24px",
    borderRadius: "16px",
    display: "grid",
    gridTemplateColumns:
      "repeat(auto-fit,minmax(180px,1fr))",
    gap: "15px",
    marginBottom: "35px",
    boxShadow:
      "0 4px 12px rgba(0,0,0,0.05)"
  },

  input: {
    padding: "14px",
    borderRadius: "10px",
    border: "1px solid #d1d5db",
    outline: "none"
  },

  searchBtn: {
    background: "#2563eb",
    color: "white",
    border: "none",
    borderRadius: "10px",
    cursor: "pointer",
    fontWeight: "500"
  },

  empty: {
    background: "white",
    padding: "30px",
    borderRadius: "14px",
    textAlign: "center",
    color: "#6b7280"
  },

  grid: {
    display: "grid",
    gridTemplateColumns:
